"use client";

import { Container } from "../components/container";
import { Heading } from "../components/text";

interface MisconceptionWrapperProps {
  children: React.ReactNode;
  hook: string;
  reality: string;
}

export function MisconceptionWrapper({
  hook,
  reality,
  children,
}: MisconceptionWrapperProps) {
  return (
    <Container className="py-24">
      <div className="mb-12 max-w-2xl">
        <p className="font-semibold text-red-500 text-sm uppercase tracking-wider">
          Misconception
        </p>
        <Heading as="h3" className="mt-2">
          &ldquo;{hook}&rdquo;
        </Heading>
        <p className="mt-4 text-gray-600 text-lg dark:text-gray-400">
          {reality}
        </p>
      </div>
      {children}
    </Container>
  );
}

import type { Metadata } from "next";
import { CounterDesktop } from "./(counter)/counter-desktop";
import { CounterMobile } from "./(counter)/counter-mobile";
import { MisconceptionWrapper } from "./(demos)/misconception-wrapper";
import { Container } from "./components/container";
import { Digest } from "./components/digest";
import { FrequentlyAskedQuestions } from "./components/faqs";
import { Footer } from "./components/footer";
import { Gradient } from "./components/gradient";
import { MarketingButton } from "./components/marketing-button";
import { Navbar } from "./components/navbar";
import { Heading, Subheading } from "./components/text";

export const metadata: Metadata = {
  title: "hasToggle — Build more. Type less.",
  description:
    "Learn to build production web apps by directing AI. Weekly misconception-busting content for AI-empowered developers.",
};

function Hero() {
  return (
    <div className="relative">
      <Gradient className="absolute inset-2 inset-ring inset-ring-black/5 bottom-0 rounded-4xl" />
      <Container className="relative">
        <Navbar variant="dark" />
        <div className="pt-16 pb-24 sm:pt-24 sm:pb-32 md:pt-32 md:pb-48">
          <h1 className="max-w-64 font-display font-medium text-6xl/[0.9] text-ht-blue-200 tracking-tight sm:max-w-sm sm:text-8xl/[0.8] md:max-w-md md:text-9xl/[0.8] lg:max-w-full">
            Build more. Type less.
          </h1>
          <p className="mt-8 max-w-lg font-medium text-gray-50/90 text-xl/7 sm:text-2xl/8">
            Learn to build production web apps by directing AI — not memorizing
            syntax. hasToggle teaches you to orchestrate, review, and ship.
          </p>
          <div className="mt-12 flex flex-col gap-x-6 gap-y-4 sm:flex-row">
            <MarketingButton href="#digest">
              Get the weekly misconception buster
            </MarketingButton>
          </div>
        </div>
      </Container>
    </div>
  );
}

function MisconceptionDemos() {
  return (
    <div>
      {/* Demo 1: React State */}
      <MisconceptionWrapper
        hook="AI writes the code so I don't need to understand it."
        reality="AI helps you type code, but you still need to understand how things work. Watch how React re-runs your function to get updated values."
      >
        <div className="relative mt-10 aspect-1216/768">
          <div className="lg:hidden">
            <CounterMobile />
          </div>
          <div className="hidden lg:block">
            <CounterDesktop />
          </div>
        </div>
      </MisconceptionWrapper>

      {/* Demo 2: Optimistic Updates — placeholder */}
      <div className="bg-gray-900">
        <MisconceptionWrapper
          hook="The user can wait."
          reality="Perceived quality comes from UX patterns like optimistic updates. AI can implement them — but you need to know to ask."
        >
          <p className="text-gray-400">Demo coming soon</p>
        </MisconceptionWrapper>
      </div>

      {/* Demo 3: Just a Button — link to existing page */}
      <MisconceptionWrapper
        hook="It's just a button, how hard can it be?"
        reality="A button is a full-stack concern: validation, optimistic UI, error handling, auth, and database access."
      >
        <p className="text-gray-500">
          <a className="underline" href="/misconceptions/just-a-button">
            Explore the full demo →
          </a>
        </p>
      </MisconceptionWrapper>
    </div>
  );
}

function About() {
  return (
    <div className="bg-gray-50 dark:bg-gray-900">
      <Container className="py-24">
        <div className="mx-auto max-w-2xl text-center">
          <Subheading>About</Subheading>
          <Heading as="h3" className="mt-2">
            AI amplifies. It doesn&apos;t replace.
          </Heading>
          <p className="mt-6 text-gray-600 text-lg leading-8 dark:text-gray-400">
            hasToggle is built on a simple idea: AI is the best thing that
            happened to individual developers. It manages cognitive complexity
            so you can focus on what matters — architecture, product decisions,
            and shipping. You&apos;re not learning to type code. You&apos;re
            learning to build.
          </p>
          <p className="mt-4 text-gray-500 text-sm">
            Created by Eric — developer, educator, and believer in AI-empowered
            individuals.
          </p>
        </div>
      </Container>
    </div>
  );
}

function DigestCTA() {
  return (
    <Container className="py-24">
      <div className="mx-auto max-w-2xl text-center" id="digest">
        <Heading as="h3">One misconception, busted every week.</Heading>
        <p className="mt-4 text-gray-600 text-lg dark:text-gray-400">
          The hasToggle digest delivers a weekly misconception about AI and web
          development — and shows you why it&apos;s wrong. Straight to your
          inbox.
        </p>
        <div className="mt-8">
          <Digest />
        </div>
      </div>
    </Container>
  );
}

export default function MarketingPage() {
  return (
    <div className="overflow-hidden">
      <Hero />
      <main>
        <MisconceptionDemos />
        <About />
        <DigestCTA />
        <FrequentlyAskedQuestions />
      </main>
      <Footer />
    </div>
  );
}

import { Container } from "./container";
import { Heading, Subheading } from "./text";

const courseFrequentlyAskedQuestions = [
  {
    question: "Do I need to know how to code already?",
    answer:
      "No, but you\u2019ll learn how software works so you can direct AI effectively. hasToggle starts from the fundamentals and builds up to production-level web apps. The goal isn\u2019t to memorize syntax \u2014 it\u2019s to understand how things fit together so you can orchestrate AI to build what you envision.",
  },
  {
    question: "Is this just another prompt engineering course?",
    answer:
      "No. You learn to build real web apps by orchestrating AI agents, not just writing prompts. hasToggle teaches architecture, debugging, code review, and shipping \u2014 the skills that matter when AI is doing the typing.",
  },
  {
    question: "What if AI gets it wrong?",
    answer:
      "That\u2019s exactly why you need to understand the fundamentals. AI is powerful but not infallible. We teach you to review, debug, and guide AI so you catch mistakes before they ship. Understanding how code works is what separates builders from prompt-typists.",
  },
  {
    question: "What tech stack will I learn?",
    answer:
      "Next.js, React, TypeScript, and modern AI tools \u2014 the same stack used to build hasToggle itself. You\u2019ll learn fullstack web development with the tools that professional teams actually use in production.",
  },
  {
    question: "What\u2019s in the weekly digest?",
    answer:
      "One misconception about AI or web development, busted with an explanation of what\u2019s actually true. Each edition is short, practical, and designed to sharpen your mental model of how modern web development really works.",
  },
];

export function FrequentlyAskedQuestions() {
  return (
    <section
      aria-labelledby="faq-title"
      className="relative overflow-hidden bg-slate-50 py-20 sm:py-32"
      id="faq"
    >
      <Container>
        <section className="scroll-mt-8" id="faqs">
          <Subheading className="text-center">
            Frequently asked questions
          </Subheading>
          <Heading as="div" className="mt-2 text-center">
            Your questions answered.
          </Heading>
          <div className="mx-auto mt-16 mb-32 max-w-xl space-y-12">
            {courseFrequentlyAskedQuestions.map((faq) => (
              <dl key={faq.question}>
                <dt className="font-semibold text-base">{faq.question}</dt>
                <dd className="mt-4 text-gray-600 text-sm/6">{faq.answer}</dd>
              </dl>
            ))}
          </div>
        </section>
      </Container>
    </section>
  );
}

import { Container } from "./container";
import { Digest } from "./digest";
import { Gradient } from "./gradient";
import { Logo } from "./logo";
import { Link } from "./marketing-link";
import { PlusGrid, PlusGridItem, PlusGridRow } from "./plus-grid";
import { Subheading } from "./text";

function CallToAction() {
  return (
    <div className="relative pt-20 pb-16 text-center sm:py-24">
      <hgroup>
        <Subheading>Stay sharp</Subheading>
        <p className="mt-6 font-medium text-3xl text-gray-950 tracking-tight sm:text-5xl">
          One misconception, busted weekly.
          <br />
          Sign up for the digest.
        </p>
      </hgroup>
      <p className="mx-auto mt-6 max-w-xs text-gray-500 text-sm/6">
        AI-empowered web development insights, every Monday.
      </p>

      <Digest />
    </div>
  );
}

function SitemapHeading({ children }: { children: React.ReactNode }) {
  return <h3 className="font-medium text-gray-950/50 text-sm/6">{children}</h3>;
}

function SitemapLinks({ children }: { children: React.ReactNode }) {
  return <ul className="mt-6 space-y-4 text-sm/6">{children}</ul>;
}

function SitemapLink(props: React.ComponentPropsWithoutRef<typeof Link>) {
  return (
    <li>
      <Link
        {...props}
        className="font-medium text-gray-950 hover:text-gray-950/75"
      />
    </li>
  );
}

function Sitemap() {
  return (
    <div>
      <SitemapHeading>Product</SitemapHeading>
      <SitemapLinks>
        <SitemapLink href="/#faq">FAQs</SitemapLink>
      </SitemapLinks>
    </div>
  );
}

function SocialIconX(props: React.ComponentPropsWithoutRef<"svg">) {
  return (
    <svg aria-hidden="true" fill="currentColor" viewBox="0 0 16 16" {...props}>
      <path d="M12.6 0h2.454l-5.36 6.778L16 16h-4.937l-3.867-5.594L2.771 16H.316l5.733-7.25L0 0h5.063l3.495 5.114L12.6 0zm-.86 14.376h1.36L4.323 1.539H2.865l8.875 12.837z" />
    </svg>
  );
}

function SocialIconYouTube(props: React.ComponentPropsWithoutRef<"svg">) {
  return (
    <svg
      aria-hidden="true"
      fill="currentColor"
      viewBox="0 0 576 512"
      {...props}
    >
      <path d="M549.7 124.1c-6.3-23.7-24.8-42.3-48.3-48.6C458.8 64 288 64 288 64S117.2 64 74.6 75.5c-23.5 6.3-42 24.9-48.3 48.6-11.4 42.9-11.4 132.3-11.4 132.3s0 89.4 11.4 132.3c6.3 23.7 24.8 41.5 48.3 47.8C117.2 448 288 448 288 448s170.8 0 213.4-11.5c23.5-6.3 42-24.2 48.3-47.8 11.4-42.9 11.4-132.3 11.4-132.3s0-89.4-11.4-132.3zm-317.5 213.5V175.2l142.7 81.2-142.7 81.2z" />
    </svg>
  );
}

function SocialIconLinkedIn(props: React.ComponentPropsWithoutRef<"svg">) {
  return (
    <svg aria-hidden="true" fill="currentColor" viewBox="0 0 16 16" {...props}>
      <path d="M14.82 0H1.18A1.169 1.169 0 000 1.154v13.694A1.168 1.168 0 001.18 16h13.64A1.17 1.17 0 0016 14.845V1.15A1.171 1.171 0 0014.82 0zM4.744 13.64H2.369V5.996h2.375v7.644zm-1.18-8.684a1.377 1.377 0 11.52-.106 1.377 1.377 0 01-.527.103l.007.003zm10.075 8.683h-2.375V9.921c0-.885-.015-2.025-1.234-2.025-1.218 0-1.425.966-1.425 1.968v3.775H6.233V5.997H8.51v1.05h.032c.317-.601 1.09-1.235 2.246-1.235 2.405-.005 2.851 1.578 2.851 3.63v4.197z" />
    </svg>
  );
}

function SocialLinks() {
  return (
    <>
      <Link
        aria-label="Visit Eric on YouTube"
        className="text-gray-950 hover:text-gray-950/75"
        href="https://www.youtube.com/@hastoggle"
        target="_blank"
      >
        <SocialIconYouTube className="size-6" />
      </Link>
      <Link
        aria-label="DM Eric on X"
        className="text-gray-950 hover:text-gray-950/75"
        href="https://x.com/hasToggle"
        target="_blank"
      >
        <SocialIconX className="size-4" />
      </Link>
      <Link
        aria-label="Connect with Eric on LinkedIn"
        className="text-gray-950 hover:text-gray-950/75"
        href="https://www.linkedin.com/in/ernst-stolz"
        target="_blank"
      >
        <SocialIconLinkedIn className="size-4" />
      </Link>
    </>
  );
}

function Copyright() {
  return (
    <div className="text-gray-950 text-sm/6">
      &copy; {new Date().getFullYear()} hasToggle.
    </div>
  );
}

export function Footer() {
  return (
    <footer>
      <Gradient className="relative">
        <div className="absolute inset-2 rounded-4xl bg-slate-50/90" />
        <Container>
          <CallToAction />
          <PlusGrid className="pb-16">
            <PlusGridRow>
              <div className="grid grid-cols-2 gap-y-10 pb-6 lg:grid-cols-6 lg:gap-8">
                <div className="col-span-2 flex">
                  <PlusGridItem className="pt-6 lg:pb-6">
                    <Logo className="inline-block h-6" fill="black" />
                  </PlusGridItem>
                </div>
                <div className="col-span-2 grid grid-cols-2 gap-x-8 gap-y-12 lg:col-span-4 lg:grid-cols-subgrid lg:pt-6">
                  <Sitemap />
                </div>
              </div>
            </PlusGridRow>
            <PlusGridRow className="flex justify-between">
              <div>
                <PlusGridItem className="py-3">
                  <Copyright />
                </PlusGridItem>
              </div>
              <div>
                <div className="py-3 text-center text-gray-500 text-sm/6">
                  build more, type less
                </div>
              </div>
              <div className="flex">
                <PlusGridItem className="flex items-center gap-8 py-3">
                  <SocialLinks />
                </PlusGridItem>
              </div>
            </PlusGridRow>
          </PlusGrid>
        </Container>
      </Gradient>
    </footer>
  );
}

