        >
          &#9656;
        </span>
        {label}
      </button>
      {open && (
        <div
          className={cn(
            "mt-4 text-sm/6",
            dark
              ? "text-gray-400"
              : "text-gray-600 dark:text-gray-400"
          )}
        >
          {children}
        </div>
      )}
    </div>
  );
}

